// Helper to get random enemies by tier
export function getEnemiesByTier(tier) {
  return ENEMIES.filter(e => e.tier === tier)
}

// Get enemies for a specific dungeon floor
export function getEnemiesForFloor(floor) {
  if (floor <= 5) return getEnemiesByTier(1)
  if (floor <= 10) return [...getEnemiesByTier(1), ...getEnemiesByTier(2)]
  if (floor <= 18) return [...getEnemiesByTier(2), ...getEnemiesByTier(3)]
  if (floor <= 28) return [...getEnemiesByTier(3), ...getEnemiesByTier(4)]
  return [...getEnemiesByTier(4), ...getEnemiesByTier(5)]
}

export function pickRandomEnemy(floor) {
  const pool = getEnemiesForFloor(floor)
  return pool[Math.floor(Math.random() * pool.length)]
}
